def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    es_config = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'max_retries': 3,
        'retry_on_timeout': True,
        'request_timeout': 10,
        'maxsize': 25,  # Connection pool size for high traffic
    }

    if ES_USERNAME and ES_PASSWORD:
        es_config['basic_auth'] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**es_config)


# Initialize ES client at module level for connection reuse
es_client = get_es_client()


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       in_stock=None, sort_by=None, sort_order='desc'):
    """Build an Elasticsearch query with multi-match, filters, and boosting."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search with multi-match across relevant fields
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',           # Boost product name matches
                    'name.autocomplete^2',
                    'description^1.5',
                    'brand^2',
                    'category^1',
                    'tags^1',
                    'sku^4',            # Exact SKU matches boosted highest
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%',
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # In-stock filter
    if in_stock is not None:
        filter_clauses.append({
            'term': {'in_stock': in_stock}
        })

    # Build the complete query
    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses,
            'should': [
                # Boost products that are in stock
                {'term': {'in_stock': {'value': True, 'boost': 2.0}}},
                # Boost products with higher ratings
                {'range': {'rating': {'gte': 4.0, 'boost': 1.5}}},
                # Boost featured products
                {'term': {'featured': {'value': True, 'boost': 3.0}}},
            ]
        }
    }

    # Sort configuration
    sort = []
    if sort_by == 'price':
        sort.append({'price': {'order': sort_order}})
    elif sort_by == 'rating':
        sort.append({'rating': {'order': sort_order}})
    elif sort_by == 'newest':
        sort.append({'created_at': {'order': 'desc'}})
    elif sort_by == 'name':
        sort.append({'name.keyword': {'order': sort_order}})

    # Always add relevance score as secondary sort
    sort.append('_score')

    return query, sort


def build_aggregations():
    """Build aggregations for faceted search."""
    return {
        'categories': {
            'terms': {
                'field': 'category.keyword',
                'size': 50
            }
        },
        'brands': {
            'terms': {
                'field': 'brand.keyword',
                'size': 50
            }
        },
        'price_ranges': {
            'range': {
                'field': 'price',
                'ranges': [
                    {'key': 'under_25', 'to': 25},
                    {'key': '25_to_50', 'from': 25, 'to': 50},
                    {'key': '50_to_100', 'from': 50, 'to': 100},
                    {'key': '100_to_200', 'from': 100, 'to': 200},
                    {'key': 'over_200', 'from': 200},
                ]
            }
        },
        'avg_price': {
            'avg': {'field': 'price'}
        },
        'in_stock_count': {
            'filter': {'term': {'in_stock': True}}
        }
    }


def format_search_results(es_response, page, page_size):
    """Format Elasticsearch response into a clean API response."""
    hits = es_response.get('hits', {})
    total = hits.get('total', {})
    total_count = total.get('value', 0) if isinstance(total, dict) else total

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit.get('_id')
        product['score'] = hit.get('_score')

        # Include highlights if available
        if 'highlight' in hit:
            product['highlights'] = hit['highlight']

        products.append(product)

    # Format aggregations
    aggs = es_response.get('aggregations', {})
    facets = {}

    if 'categories' in aggs:
        facets['categories'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['categories'].get('buckets', [])
        ]

    if 'brands' in aggs:
        facets['brands'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['brands'].get('buckets', [])
        ]

    if 'price_ranges' in aggs:
        facets['price_ranges'] = [
            {'range': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['price_ranges'].get('buckets', [])
        ]

    if 'avg_price' in aggs:
        facets['avg_price'] = aggs['avg_price'].get('value')

    if 'in_stock_count' in aggs:
        facets['in_stock_count'] = aggs['in_stock_count'].get('doc_count', 0)

    # Pagination metadata
    total_pages = (total_count + page_size - 1) // page_size if page_size > 0 else 0

    return {
        'products': products,
        'pagination': {
            'total': total_count,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_prev': page > 1,
        },
        'facets': facets,
    }


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Search products endpoint.

    Query Parameters:
        q (str): Search keyword (required)
        page (int): Page number (default: 1)
        page_size (int): Results per page (default: 20, max: 100)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        in_stock (bool): Filter by stock availability
        sort_by (str): Sort field (price, rating, newest, name)
        sort_order (str): Sort order (asc, desc)
        facets (bool): Include faceted search aggregations (default: true)

    Returns:
        JSON response with products, pagination, and facets
    """
    start_time = time.time()

    # Extract and validate query parameters
    keyword = request.args.get('q', '').strip()
    if not keyword:
        return jsonify({
            'error': 'Missing required parameter',
            'message': 'Query parameter "q" is required',
        }), 400

    if len(keyword) > 500:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'Query parameter "q" must be 500 characters or fewer',
        }), 400

    # Pagination
    try:
        page = max(1, int(request.args.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(MAX_PAGE_SIZE, max(1, int(request.args.get('page_size', DEFAULT_PAGE_SIZE))))
    except (ValueError, TypeError):
        page_size = DEFAULT_PAGE_SIZE

    # Prevent deep pagination (protect ES from excessive memory usage)
    max_offset = 10000
    offset = (page - 1) * page_size
    if offset + page_size > max_offset:
        return jsonify({
            'error': 'Pagination limit exceeded',
            'message': f'Cannot paginate beyond {max_offset} results. Use more specific search terms.',
        }), 400

    # Filters
    category = request.args.get('category', '').strip() or None

    min_price = None
    max_price = None
    try:
        if request.args.get('min_price'):
            min_price = float(request.args.get('min_price'))
            if min_price < 0:
                return jsonify({'error': 'Invalid parameter', 'message': 'min_price must be non-negative'}), 400
    except (ValueError, TypeError):
        return jsonify({'error': 'Invalid parameter', 'message': 'min_price must be a valid number'}), 400

    try:
        if request.args.get('max_price'):
            max_price = float(request.args.get('max_price'))
            if max_price < 0:
                return jsonify({'error': 'Invalid parameter', 'message': 'max_price must be non-negative'}), 400
    except (ValueError, TypeError):
        return jsonify({'error': 'Invalid parameter', 'message': 'max_price must be a valid number'}), 400

    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({'error': 'Invalid parameter', 'message': 'min_price cannot be greater than max_price'}), 400

    in_stock = None
    in_stock_param = request.args.get('in_stock')
    if in_stock_param is not None:
        in_stock = in_stock_param.lower() in ('true', '1', 'yes')

    # Sorting
    sort_by = request.args.get('sort_by')
    if sort_by and sort_by not in ('price', 'rating', 'newest', 'name'):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'sort_by must be one of: price, rating, newest, name',
        }), 400

    sort_order = request.args.get('sort_order', 'desc').lower()
    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    # Facets
    include_facets = request.args.get('facets', 'true').lower() in ('true', '1', 'yes')

    # Build the search query
    query, sort = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        in_stock=in_stock,
        sort_by=sort_by,
        sort_order=sort_order,
    )

    # Build the ES search body
    search_body = {
        'query': query,
        'sort': sort,
        'from': offset,
        'size': page_size,
        'timeout': SEARCH_TIMEOUT,
        'highlight': {
            'fields': {
                'name': {'number_of_fragments': 1, 'fragment_size': 150},
                'description': {'number_of_fragments': 2, 'fragment_size': 150},
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>'],
        },
        '_source': {
            'includes': [
                'name', 'description', 'price', 'category', 'brand',
                'image_url', 'rating', 'review_count', 'in_stock',
                'sku', 'tags', 'featured', 'created_at', 'updated_at',
            ]
        },
        'track_total_hits': True,
    }

    if include_facets:
        search_body['aggregations'] = build_aggregations()

    # Execute search
    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
        )
    except Exception as e:
        logger.error(f"Elasticsearch search error: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Search service unavailable',
            'message': 'Unable to perform search at this time. Please try again later.',
        }), 503

    # Format results
    result = format_search_results(es_response, page, page_size)

    # Add metadata
    elapsed_time = time.time() - start_time
    es_took = es_response.get('took', 0)
    timed_out = es_response.get('timed_out', False)

    result['meta'] = {
        'query': keyword,
        'took_ms': round(elapsed_time * 1000, 2),
        'es_took_ms': es_took,
        'timed_out': timed_out,
    }

    if timed_out:
        logger.warning(f"Search timed out for query: '{keyword}'")

    # Log search metrics for monitoring
    logger.info(
        f"Search query='{keyword}' results={result['pagination']['total']} "
        f"page={page} took={result['meta']['took_ms']}ms es_took={es_took}ms"
    )

    response = jsonify(result)
    # Cache headers for CDN/reverse proxy caching during high traffic
    response.headers['Cache-Control'] = 'public, max-age=30, stale-while-revalidate=60'
    response.headers['Vary'] = 'Accept-Encoding'

    return response, 200


